        for (int i = valueList.size(); i < option.getMinArgs(); i++) {
            if (defaultValues != null && i < defaultValues.size()) {
                tempList.add(defaultValues.get(i));
            } else if (this.defaultValues.get(option) != null && i - defaultValues.size() < this.defaultValues.get(option).size()) {
                tempList.add(this.defaultValues.get(option).get(i - defaultValues.size()));
            }
        }
        valueList = tempList;
    }

    return valueList == null ? Collections.EMPTY_LIST : valueList;
}
